param(
    [Parameter(Mandatory=$false)]
    [string]$AppName,

    [Parameter(Mandatory=$false)]
    [string]$Path
)

# Common application paths
$appPaths = @{
    "word" = "WINWORD.EXE"
    "excel" = "EXCEL.EXE"
    "powerpoint" = "POWERPNT.EXE"
    "notepad" = "notepad.exe"
    "calc" = "calc.exe"
    "chrome" = "chrome.exe"
    "edge" = "msedge.exe"
    "explorer" = "explorer.exe"
    "outlook" = "OUTLOOK.EXE"
    "onenote" = "ONENOTE.EXE"
    "teams" = "Teams.exe"
    "paint" = "mspaint.exe"
    "cmd" = "cmd.exe"
    "powershell" = "powershell.exe"
}

try {
    if ($Path) {
        # Launch using custom path
        if (Test-Path $Path) {
            Write-Host "Opening: $Path"
            Start-Process $Path
            Write-Host "SUCCESS: Application launched"
        } else {
            Write-Host "ERROR: File not found: $Path"
            exit 1
        }
    } elseif ($AppName) {
        $AppName = $AppName.ToLower()

        if ($appPaths.ContainsKey($AppName)) {
            $exeName = $appPaths[$AppName]
            Write-Host "Opening: $exeName"
            Start-Process $exeName
            Write-Host "SUCCESS: $AppName launched"
        } else {
            Write-Host "ERROR: Unknown application: $AppName"
            Write-Host "Available apps: $($appPaths.Keys -join ', ')"
            exit 1
        }
    } else {
        Write-Host "ERROR: Please provide either -AppName or -Path"
        Write-Host "Usage:"
        Write-Host "  .\open_app.ps1 -AppName 'word'"
        Write-Host "  .\open_app.ps1 -Path 'C:\MyApp\app.exe'"
        exit 1
    }
} catch {
    Write-Host "ERROR: $_"
    exit 1
}

param(
    [Parameter(Mandatory=$true)]
    [ValidateSet("type", "hotkey", "wait", "focus", "click")]
    [string]$Action,

    [Parameter(Mandatory=$false)]
    [string]$Text,

    [Parameter(Mandatory=$false)]
    [string]$Keys,

    [Parameter(Mandatory=$false)]
    [string]$WindowTitle,

    [Parameter(Mandatory=$false)]
    [int]$TimeoutSeconds = 30
)

Add-Type -AssemblyName System.Windows.Forms
Add-Type -AssemblyName System.Drawing

function Send-Keys {
    param([string]$KeyString)

    try {
        [System.Windows.Forms.SendKeys]::SendWait($KeyString)
        Write-Host "SUCCESS: Sent keys: $KeyString"
    } catch {
        Write-Host "ERROR: Failed to send keys: $_"
        exit 1
    }
}

function Type-Text {
    param([string]$TextToType)

    try {
        # Escape special characters for SendKeys
        $escaped = $TextToType -replace '[\+\^\%\~\(\)\{\}\[\]]', '{$0}'
        [System.Windows.Forms.SendKeys]::SendWait($escaped)
        Write-Host "SUCCESS: Typed text"
    } catch {
        Write-Host "ERROR: Failed to type text: $_"
        exit 1
    }
}

function Wait-ForWindow {
    param(
        [string]$Title,
        [int]$Timeout
    )

    $endTime = (Get-Date).AddSeconds($Timeout)

    Write-Host "Waiting for window: $Title"

    while ((Get-Date) -lt $endTime) {
        $windows = Get-Process | Where-Object { $_.MainWindowTitle -like "*$Title*" }

        if ($windows) {
            Write-Host "SUCCESS: Window found: $($windows[0].MainWindowTitle)"
            return $true
        }

        Start-Sleep -Milliseconds 500
    }

    Write-Host "ERROR: Window not found within timeout"
    exit 1
}

function Focus-Window {
    param([string]$Title)

    $windows = Get-Process | Where-Object { $_.MainWindowTitle -like "*$Title*" }

    if ($windows) {
        $window = $windows[0]
        Add-Type @"
            using System;
            using System.Runtime.InteropServices;
            public class WinAPI {
                [DllImport("user32.dll")]
                public static extern bool SetForegroundWindow(IntPtr hWnd);
                [DllImport("user32.dll")]
                public static extern bool ShowWindow(IntPtr hWnd, int nCmdShow);
            }
"@
        [WinAPI]::ShowWindow($window.MainWindowHandle, 9)  # SW_RESTORE
        [WinAPI]::SetForegroundWindow($window.MainWindowHandle)
        Write-Host "SUCCESS: Focused window: $($window.MainWindowTitle)"
    } else {
        Write-Host "ERROR: Window not found: $Title"
        exit 1
    }
}

try {
    switch ($Action) {
        "type" {
            if (-not $Text) {
                Write-Host "ERROR: -Text parameter required for 'type' action"
                exit 1
            }
            Start-Sleep -Milliseconds 100
            Type-Text -TextToType $Text
        }

        "hotkey" {
            if (-not $Keys) {
                Write-Host "ERROR: -Keys parameter required for 'hotkey' action"
                exit 1
            }
            Start-Sleep -Milliseconds 100
            Send-Keys -KeyString $Keys
        }

        "wait" {
            if (-not $WindowTitle) {
                Write-Host "ERROR: -WindowTitle parameter required for 'wait' action"
                exit 1
            }
            Wait-ForWindow -Title $WindowTitle -Timeout $TimeoutSeconds
        }

        "focus" {
            if (-not $WindowTitle) {
                Write-Host "ERROR: -WindowTitle parameter required for 'focus' action"
                exit 1
            }
            Focus-Window -Title $WindowTitle
        }

        "click" {
            Write-Host "Click action requires coordinates (not yet implemented)"
            Write-Host "Use hotkey with TAB/ENTER to navigate UI"
            exit 1
        }
    }
} catch {
    Write-Host "ERROR: $_"
    exit 1
}

